    englishName: "The Relief",
    frenchName: "L'Ouverture",
    verses: [
      { number: 1, arabic: "أَلَمْ نَشْرَحْ لَكَ صَدْرَكَ", french: "N'avons-Nous pas ouvert pour toi ta poitrine ?" },
      { number: 2, arabic: "وَوَضَعْنَا عَنكَ وِزْرَكَ", french: "Et ne t'avons-Nous pas déchargé du fardeau" },
      { number: 3, arabic: "الَّذِي أَنقَضَ ظَهْرَكَ", french: "qui accablait ton dos ?" },
      { number: 4, arabic: "وَرَفَعْنَا لَكَ ذِكْرَكَ", french: "Et n'avons-Nous pas exalté pour toi ta renommée ?" },
      { number: 5, arabic: "فَإِنَّ مَعَ الْعُسْرِ يُسْرًا", french: "À côté de la difficulté est, certes, une facilité !" },
      { number: 6, arabic: "إِنَّ مَعَ الْعُسْرِ يُسْرًا", french: "Oui, à côté de la difficulté est, certes, une facilité !" },
      { number: 7, arabic: "فَإِذَا فَرَغْتَ فَانصَبْ", french: "Quand tu te libères, donc, fournis encore un effort," },
      { number: 8, arabic: "وَإِلَىٰ رَبِّكَ فَارْغَب", french: "et vers ton Seigneur, aspire." }
    ]
